class SuperMLP(nn.Module) {
  __init__(config) = {
    hidden_size=config.hidden_size,
    intermediate_size=config.intermediate_size,
    gate_proj=Linear(hidden_size, intermediate_size, bias=config.mlp_bias),
    up_proj=Linear(hidden_size, intermediate_size, bias=config.mlp_bias),
    down_proj=Linear(intermediate_size, hidden_size, bias=config.mlp_bias),
    act_fn=ACT2FN[config.hidden_act]
  }

  forward(x) = down_proj(act_fn(gate_proj(x)) * up_proj(x))
}
